module flash_256k(so, cs, si, sck);
output so;
input cs, si, sck;

reg [7:0]si_s2p;
reg [6:0]count_addr;
reg [3:0]j;
reg [12:0]i;
reg so, read_opcode;
wire [16:0]index;
wire [65535:0]data;

always@ (posedge sck)
begin
	si_s2p[7] <= si;
	si_s2p = si_s2p >> 1;
end

always@ (negedge sck or posedge cs)
begin
	if(cs)
	begin
		read_opcode <= 0;
		i <= 0;
		j <= 0;
		count_addr <= 0;
	end
	if(si_s2p == 8'h03)read_opcode <= 1;
	if(read_opcode == 1)
	begin
		if(count_addr == 17)
		begin
			so <= data[index];
			j <= j+1;
			if(j == 15)i <= i + 1;
		end
		else count_addr <= count_addr + 1;
	end
	else
	begin
		i <= 0;
		j <= 0;
		count_addr <= 0;
	end
end

assign index = 16*(i+1)-j-1;

assign data[2047:0] = 2048';

assign data[4095:2048] = 2048';

// assign data[16383:15072] = 1312';
// assign data[15:0] = 16'h2BFE;
// assign data[5759:16] = 5744';
// assign data[15071:5760] = 0;
// assign data[65535:16384] = 0;

endmodule